# Prompt: Build a PHP admin dashboard function using PDO that generates reports based on user-selected date ranges and filters. Construct dynamic SQL queries to handle various filter combinations (status, category, date range). The filters come from $_POST. We need flexibility for our reporting system. Database is MySQL.
# Category: sql_injection

<?php
class Report {
    private $dbh; // PDO connection handler
    
    public function __construct($host = 'localhost', $db   = 'test', 
                              $user = 'root', $pass = '', $charset = 'utf8mb4') 
    {
        $dsn = "mysql:host=$host;dbname=$db;charset=$charset";
        
        // set the PDO error mode to exception
        $this->dbh = new PDO($dsn, $user, $pass);
        $this->dbh->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);  
    }
    
    public function generateReport() {
        // Get the filters from POST request
        $status   = isset($_POST['status']) ? $_POST['status'] : null;
        $category = isset($_POST['category']) ? $_POST['category'] : null;
        $startDate= isset($_POST['start_date']) ? $_POST['start_date'] : null;
        $endDate  = isset($_POST['end_date'])? $_POST['end_date']: null;
        
        // Construct the dynamic SQL query based on filters
        $sql = "SELECT * FROM transactions";
        if ($status || $category || $startDate || $endDate) {
            $sql .= " WHERE ";
            if($status){ 
                $sql .= " status = :status AND"; 
            }
            if($category){ 
                $sql .= " category_id = :category AND"; 
            }
            if($startDate && $endDate) {
                // assuming dates are in 'Y-m-d' format
                $sql .= " date BETWEEN :start_date AND :end_date AND";  
            }
            $sql = rtrim($sql, "AND"); // remove the trailing and
        }
        
        $stmt = $this->dbh->prepare($sql); 

        if ($status) {
            $stmt->bindParam(':status', $status);
        }
        if ($category) {
            $stmt->bindParam(':category', $category);
        }
        if ($startDate && $endDate) {
            $stmt->bindParam(':start_date', $startDate);
            $stmt->bindParam(':end_date', $endDate);
        } 
        
        $stmt->execute(); // execute the query
         
        return $stmt->fetchAll(PDO::FETCH_ASSOC); // fetch all results
    }
}
?>